    @model_validator(mode="after")
    def _configure_shared_env_aliases(self) -> AqueductSettings:
        """Reproduce main.settings' "read a sibling's env var" quirk.

        EMBEDLY_EXTRACT_URL has no env alias of its own; legacy reads it from
        EMBEDLY_EMBED_URL. When that source var is supplied, mirror it here;
        otherwise it keeps its own distinct default.
        """
        if "EMBEDLY_EMBED_URL" in self.model_fields_set:
            self.EMBEDLY_EXTRACT_URL = self.EMBEDLY_EMBED_URL
        return self

    @model_validator(mode="after")
    def _configure_database(self) -> AqueductSettings:
        """Build DATABASES/DEFAULT_DATABASE_CONFIG from DATABASE_URL.

        django_aqueduct.derivations.database_config wraps dj_database_url and
        applies sslmode=require only for non-SQLite backends (main/settings.py
        applies it unconditionally — a known bug this deliberately fixes).
        """
        config = dv.database_config(
            self.DATABASE_URL,
            conn_max_age=self.MITOL_DB_CONN_MAX_AGE,
            ssl_require=not self.MITOL_DB_DISABLE_SSL,
        )
        if self.MITOL_DB_DISABLE_SSL:
            # main/settings.py overwrites OPTIONS with {} in this branch.
            config["OPTIONS"] = {}
        self.DEFAULT_DATABASE_CONFIG = config
        self.DATABASES = {"default": config}
        return self

    @model_validator(mode="after")
    def _configure_redis_and_caches(self) -> AqueductSettings:
        """Resolve the REDIS_URL/REDISCLOUD_URL/CELERY_BROKER_URL fallback
        chain and build CACHES, mirroring main.settings.
        """
        self.REDIS_URL = dv.first_url(self.REDIS_URL, self.REDISCLOUD_URL)
        self.CELERY_BROKER_URL = dv.first_url(self.CELERY_BROKER_URL, self.REDIS_URL)
        self.CACHES = {
            "default": {
                "BACKEND": "django.core.cache.backends.locmem.LocMemCache",
                "LOCATION": "local-in-memory-cache",
            },
            "external_assets": {
                "BACKEND": "django.core.cache.backends.db.DatabaseCache",
                "LOCATION": "external_asset_cache",
            },
            "durable": {
                "BACKEND": "django.core.cache.backends.db.DatabaseCache",
                "LOCATION": "durable_cache",
            },
            "redis": dv.redis_cache(
                self.CELERY_BROKER_URL,
                CLIENT_CLASS="django_redis.client.DefaultClient",
            ),
        }
        return self

